import React from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Dimensions,

} from 'react-native';
import { theme } from '../styles/theme';
import LinearGradient from 'react-native-linear-gradient';
const { width, height } = Dimensions.get('window');

export default function WelcomeScreen({ navigation }) {
  return (
    <LinearGradient
      colors={['#1a73e8', '#4285f4', '#64b5f6']}
      style={styles.container}
      start={{ x: 0, y: 0 }}
      end={{ x: 1, y: 1 }}
    >
      <View style={styles.contentContainer}>
        {/* Header/Logo Section */}
        <View style={styles.headerSection}>
          <View style={styles.logoContainer}>
            <Text style={styles.logoIcon}>💧</Text>
          </View>
          <Text style={styles.title}>AquaSmart</Text>
          <Text style={styles.subtitle}>
            IoT-Based Rainwater Harvesting System
          </Text>
        </View>

        {/* Middle Content */}
        <View style={styles.middleSection}>
          <View style={styles.featureCard}>
            <Text style={styles.featureIcon}>📊</Text>
            <Text style={styles.featureText}>Monitor</Text>
          </View>
          <View style={styles.featureCard}>
            <Text style={styles.featureIcon}>⚙️</Text>
            <Text style={styles.featureText}>Control</Text>
          </View>
          <View style={styles.featureCard}>
            <Text style={styles.featureIcon}>💚</Text>
            <Text style={styles.featureText}>Save Water</Text>
          </View>
        </View>

        {/* Tagline */}
        <View style={styles.taglineContainer}>
          <Text style={styles.description}>
            Monitor, Control & Save Water Intelligently
          </Text>
          <View style={styles.waterDropContainer}>
            <Text style={styles.waterDrop}>💧</Text>
            <Text style={styles.waterDrop}>💧</Text>
            <Text style={styles.waterDrop}>💧</Text>
          </View>
        </View>

        {/* Buttons */}
        <View style={styles.buttonContainer}>
          <TouchableOpacity
            style={styles.getStartedButton}
            onPress={() => navigation.navigate('Login')}
            activeOpacity={0.8}
          >
            <Text style={styles.getStartedText}>Get Started</Text>
          </TouchableOpacity>

          <TouchableOpacity
            style={styles.loginButton}
            onPress={() => navigation.navigate('Login')}
            activeOpacity={0.8}
          >
            <Text style={styles.loginText}>Login</Text>
          </TouchableOpacity>
        </View>

        {/* Footer */}
        <View style={styles.footer}>
          <Text style={styles.footerText}>
            Smart Water Management System
          </Text>
          <Text style={styles.footerSubtext}>
            Version 1.0 • Sustainable Technology
          </Text>
        </View>
      </View>
    </LinearGradient>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    width: '100%',
  },
  contentContainer: {
    flex: 1,
    justifyContent: 'space-between',
    paddingVertical: theme.spacing.xl * 2,
    paddingHorizontal: theme.spacing.lg,
    backgroundColor: 'rgba(255, 255, 255, 0.1)',
  },
  headerSection: {
    alignItems: 'center',
    marginTop: height * 0.05,
  },
  logoContainer: {
    width: 80,
    height: 80,
    borderRadius: 40,
    backgroundColor: 'rgba(255, 255, 255, 0.2)',
    justifyContent: 'center',
    alignItems: 'center',
    marginBottom: theme.spacing.lg,
    borderWidth: 2,
    borderColor: 'rgba(255, 255, 255, 0.3)',
  },
  logoIcon: {
    fontSize: 40,
  },
  title: {
    ...theme.typography.h1,
    fontSize: 42,
    color: '#fff',
    textAlign: 'center',
    marginBottom: theme.spacing.sm,
    textShadowColor: 'rgba(0, 0, 0, 0.3)',
    textShadowOffset: { width: 1, height: 1 },
    textShadowRadius: 3,
  },
  subtitle: {
    ...theme.typography.h2,
    fontSize: 18,
    color: '#fff',
    textAlign: 'center',
    marginBottom: theme.spacing.md,
    lineHeight: 24,
    opacity: 0.95,
    fontWeight: '500',
  },
  middleSection: {
    flexDirection: 'row',
    justifyContent: 'space-around',
    marginVertical: theme.spacing.xl,
  },
  featureCard: {
    alignItems: 'center',
    backgroundColor: 'rgba(255, 255, 255, 0.15)',
    padding: theme.spacing.md,
    borderRadius: theme.borderRadius.md,
    width: width * 0.25,
    borderWidth: 1,
    borderColor: 'rgba(255, 255, 255, 0.2)',
  },
  featureIcon: {
    fontSize: 28,
    marginBottom: theme.spacing.sm,
  },
  featureText: {
    color: '#fff',
    fontSize: 14,
    fontWeight: '600',
    textAlign: 'center',
  },
  taglineContainer: {
    alignItems: 'center',
    marginVertical: theme.spacing.xl,
  },
  description: {
    ...theme.typography.body,
    fontSize: 20,
    color: '#fff',
    textAlign: 'center',
    marginBottom: theme.spacing.lg,
    fontWeight: '600',
    textShadowColor: 'rgba(0, 0, 0, 0.2)',
    textShadowOffset: { width: 1, height: 1 },
    textShadowRadius: 2,
  },
  waterDropContainer: {
    flexDirection: 'row',
    gap: theme.spacing.lg,
  },
  waterDrop: {
    fontSize: 32,
    opacity: 0.8,
  },
  buttonContainer: {
    gap: theme.spacing.md,
    marginBottom: theme.spacing.xl,
  },
  getStartedButton: {
    backgroundColor: '#fff',
    paddingVertical: theme.spacing.lg,
    borderRadius: theme.borderRadius.lg,
    alignItems: 'center',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.2,
    shadowRadius: 8,
    elevation: 5,
  },
  getStartedText: {
    color: theme.colors.primary,
    fontSize: 18,
    fontWeight: 'bold',
  },
  loginButton: {
    backgroundColor: 'transparent',
    paddingVertical: theme.spacing.lg,
    borderRadius: theme.borderRadius.lg,
    alignItems: 'center',
    borderWidth: 2,
    borderColor: '#fff',
  },
  loginText: {
    color: '#fff',
    fontSize: 18,
    fontWeight: 'bold',
  },
  footer: {
    alignItems: 'center',
    paddingTop: theme.spacing.lg,
    borderTopWidth: 1,
    borderTopColor: 'rgba(255, 255, 255, 0.2)',
  },
  footerText: {
    color: 'rgba(255, 255, 255, 0.9)',
    fontSize: 14,
    fontWeight: '500',
    marginBottom: theme.spacing.xs,
  },
  footerSubtext: {
    color: 'rgba(255, 255, 255, 0.7)',
    fontSize: 12,
  },
});
